import test from 'node:test';
import assert from 'node:assert/strict';
import { mkdirSync, writeFileSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import {
  getGlobalGSDPreferencesPath,
  getProjectGSDPreferencesPath,
  loadGlobalGSDPreferences,
  loadProjectGSDPreferences,
} from '../src/resources/extensions/gsd/preferences.ts';

function withEnv(name, value, fn) {
  const old = process.env[name];
  process.env[name] = value;
  try {
    return fn();
  } finally {
    if (old === undefined) delete process.env[name];
    else process.env[name] = old;
  }
}

function withCwd(cwd, fn) {
  const old = process.cwd();
  process.chdir(cwd);
  try {
    return fn();
  } finally {
    process.chdir(old);
  }
}

test('global preferences use uppercase canonical path and prefer uppercase over lowercase', () => {
  const dir = join(tmpdir(), `gsd-prefs-global-${process.pid}-${Date.now()}`);
  mkdirSync(dir, { recursive: true });
  try {
    writeFileSync(join(dir, 'preferences.md'), '---\nmode: solo\n---\n', 'utf-8');
    writeFileSync(join(dir, 'PREFERENCES.md'), '---\nmode: team\n---\n', 'utf-8');
    withEnv('GSD_HOME', dir, () => {
      assert.equal(getGlobalGSDPreferencesPath(), join(dir, 'PREFERENCES.md'));
      const loaded = loadGlobalGSDPreferences();
      assert.equal(loaded?.path, join(dir, 'PREFERENCES.md'));
      assert.equal(loaded?.preferences.mode, 'team');
    });
  } finally {
    rmSync(dir, { recursive: true, force: true });
  }
});

test('project preferences use uppercase canonical path and prefer uppercase over lowercase', () => {
  const dir = join(tmpdir(), `gsd-prefs-project-${process.pid}-${Date.now()}`);
  mkdirSync(join(dir, '.gsd'), { recursive: true });
  try {
    writeFileSync(join(dir, '.gsd', 'preferences.md'), '---\nmode: solo\n---\n', 'utf-8');
    writeFileSync(join(dir, '.gsd', 'PREFERENCES.md'), '---\nmode: team\n---\n', 'utf-8');
    withCwd(dir, () => {
      assert.equal(getProjectGSDPreferencesPath(), join(dir, '.gsd', 'PREFERENCES.md'));
      const loaded = loadProjectGSDPreferences();
      assert.equal(loaded?.path, join(dir, '.gsd', 'PREFERENCES.md'));
      assert.equal(loaded?.preferences.mode, 'team');
    });
  } finally {
    rmSync(dir, { recursive: true, force: true });
  }
});

