    });
  } finally {
    rmSync(dir, { recursive: true, force: true });
  }
});

test("project preferences prefer canonical uppercase path over legacy lowercase", () => {
  const dir = join(tmpdir(), `gsd-prefs-project-${process.pid}-${Date.now()}`);
  mkdirSync(join(dir, ".gsd"), { recursive: true });
  try {
    writeFileSync(join(dir, ".gsd", "preferences.md"), "---\nmode: solo\n---\n", "utf-8");
    writeFileSync(join(dir, ".gsd", "PREFERENCES.md"), "---\nmode: team\n---\n", "utf-8");
