              <TierModelRow tier="light" modelId={routingConfig.tier_models.light} />
              <TierModelRow tier="standard" modelId={routingConfig.tier_models.standard} />
              <TierModelRow tier="heavy" modelId={routingConfig.tier_models.heavy} />
